SELECT year, market_share_percentage
FROM market_share
WHERE publisher_id = 1 AND year = 2014;

SELECT SUM(global_sales) AS total_sales_2015
FROM game_sales
WHERE year = 2015;

SELECT DISTINCT year
FROM game_sales
ORDER BY year ASC;

SELECT MAX(global_sales) AS max_sales
FROM game_sales
WHERE year = 2015;

SELECT SUM(total_sales) AS total_sales_2015_genre_2
FROM sales_trends
WHERE year = 2015 AND genre_id = 2;

SELECT game_name, global_sales
FROM game_sales
ORDER BY global_sales DESC;

SELECT SUM(total_sales) AS total_sales
FROM market_share
WHERE publisher_id = 1 AND year = 2014;
